#include <avr/wdt.h>
typedef void(*TFn)();
struct TEntry{uint32_t per;uint32_t last;TFn fn;uint32_t mxL;};
extern TEntry tasks[];
extern uint8_t ntasks;
uint8_t scheduler_tick(unsigned long now){
  uint8_t bi=0xFF;
  for(uint8_t i=0;i<ntasks;i++)
    if((now-tasks[i].last)>=tasks[i].per)
      if(bi==0xFF||tasks[i].per<tasks[bi].per)bi=i;
  if(bi==0xFF)return 0xFF;
  uint32_t t0=micros();
  tasks[bi].fn();
  uint32_t lat=micros()-t0;
  if(lat>tasks[bi].mxL)tasks[bi].mxL=lat;
  tasks[bi].last=now;
  wdt_reset();
  return bi;
}
